mapper.select:
SELECT * FROM biz_product_category
WHERE id = #{id}
  AND is_deleted = false

mapper.insert:
INSERT INTO biz_product_category (
    category_code, category_name, parent_id, level, sort_order, status, created_by, created_at
) VALUES (
    #{categoryCode}, #{categoryName}, #{parentId}, #{level}, #{sortOrder}, #{status}, #{createdBy}, CURRENT_TIMESTAMP
)

mapper.update:
UPDATE biz_product_category
SET is_deleted = true
WHERE id = #{id}

mapper.select:
SELECT COUNT(*) FROM biz_product_category
WHERE category_name = #{categoryName}
  AND is_deleted = false
